// Get HTML safely from Bright Data node
const html =
  $input.first().json.body ||
  $input.first().json.data ||
  "";

const text = html.toLowerCase();

// Financial filings distress keywords
const keywords = [
  "bankruptcy",
  "chapter 7",
  "chapter 11",
  "chapter 15",
  "liquidation",
  "restructuring",
  "default",
  "going concern",
  "credit downgrade"
];

let found = [];

for (const word of keywords) {
  if (text.includes(word)) {
    found.push(word);
  }
}

return [
  {
    source: "financial_filings",
    distressSignals: found
  }
];

const html =
  $input.first().json.body ||
  $input.first().json.data ||
  "";

const text = html.toLowerCase();

// Insolvency register focused keywords
const keywords = [
  "insolvency",
  "bankruptcy",
  "liquidation",
  "administrator",
  "receivership",
  "dissolution",
  "court filing"
];

let found = [];

for (const word of keywords) {
