  }
}

return [
  {
    source: "insolvency_register",
    distressSignals: found
  }
];

const html =
  $input.first().json.body ||
  $input.first().json.data ||
  "";

const text = html.toLowerCase();

// Financial news distress keywords
const keywords = [
  "bankruptcy",
  "insolvency",
  "financial distress",
  "missed payment",
  "default",
  "debt restructuring",
  "credit downgrade",
  "chapter 11"
];

let found = [];

for (const word of keywords) {
  if (text.includes(word)) {
    found.push(word);
  }
}

return [
  {
    source: "financial_news",
    distressSignals: found
  }
];

// Collect all distress signals WITH source tracking
let allSignals = [];
let signalDetails = [];

// Merge se multiple items aate hain
for (const item of $input.all()) {

  const source = item.json.source || "unknown";

  if (item.json.distressSignals) {

    for (const signal of item.json.distressSignals) {

      allSignals.push(signal);

      signalDetails.push({
        signal: signal,
        source: source
      });

    }
  }
}

// Remove duplicate signals (but keep detail list intact)
allSignals = [...new Set(allSignals)];


// Categorization buckets
let bankruptcy = [];
let insolvency = [];
let restructuring = [];
let filingIssues = [];

// Categorize signals
for (const signal of allSignals) {

  if (signal.includes("bankruptcy") || signal.includes("chapter")) {
    bankruptcy.push(signal);
  }

  if (signal.includes("insolvency") || signal.includes("administrator")) {
    insolvency.push(signal);
  }

  if (signal.includes("restructuring") || signal.includes("liquidation")) {
    restructuring.push(signal);
  }

  if (signal.includes("default") || signal.includes("late filing")) {
    filingIssues.push(signal);
  }
}


// Return normalized + source-aware structure
return [{
  categorizedSignals: {
    bankruptcySignals: bankruptcy,
    insolvencySignals: insolvency,
    restructuringSignals: restructuring,
    filingIssueSignals: filingIssues
  },
  allSignals: allSignals,
  signalSourceMap: signalDetails,
  sourcesAnalyzed: [...new Set(signalDetails.map(s => s.source))]
}];

