// Get AI Agent output safely
const aiOutput = items[0].json.output || {};

// Extract AI values
const distressType = aiOutput.distressType || "";
const probability = aiOutput.probability || "Low";
const aiRiskScore = aiOutput.riskScore || 0;
const explanation = aiOutput.explanation || "";

// Start with AI risk score
let correlatedScore = aiRiskScore;

// Probability weighting (conservative adjustment)
if (probability === "High") {
  correlatedScore += 10;
} else if (probability === "Medium") {
  correlatedScore += 5;
} else {
  correlatedScore += 0;
}

// Cap score between 0–100
if (correlatedScore > 100) correlatedScore = 100;
if (correlatedScore < 0) correlatedScore = 0;

// Return final structured output
return [{
  distressType,
  probability,
  aiRiskScore,
  correlatedScore,
  explanation
}];

// Get previous enriched output
const data = items[0].json;

// Extract base values safely
const distressType = data.distressType || "";
const probability = data.probability || "Low";
const aiRiskScore = data.aiRiskScore || 0;
const correlatedScore = data.correlatedScore || 0;
const explanation = data.explanation || "";
const signalSourceMap = data.signalSourceMap || [];

// Count unique sources (internal use only)
let uniqueSources = new Set();

for (const entry of signalSourceMap) {
  if (entry.source) {
    uniqueSources.add(entry.source);
  }
}

// Confidence Guardrail Logic
let confidenceLevel = "Low";
let confidenceScore = 30;

// Strong multi-source confirmation
if (uniqueSources.size >= 3 && correlatedScore > 75) {
  confidenceLevel = "High";
  confidenceScore = 90;
}
else if (uniqueSources.size === 2 && correlatedScore > 60) {
  confidenceLevel = "Medium";
  confidenceScore = 70;
}
else if (uniqueSources.size === 1) {
  confidenceLevel = "Low";
  confidenceScore = 40;
}

// News-only penalty
if (uniqueSources.size === 1 && uniqueSources.has("financial_news")) {
  confidenceScore -= 15;
  confidenceLevel = "Low";
}

// Blend AI + correlation influence
confidenceScore = Math.round(
  (confidenceScore * 0.7) + (aiRiskScore * 0.3)
);

// Cap between 0-100
if (confidenceScore > 100) confidenceScore = 100;
if (confidenceScore < 0) confidenceScore = 0;

// Final structured return
return [{
  distressType,
  probability,
  aiRiskScore,
  correlatedScore,
  confidenceLevel,
  confidenceScore,
  explanation
}];

